$p9 = [PSCustomObject]@{
    id = "REG-09"
    code = @{ ar = "REG-09"; en = "REG-09"; es = "REG-09"; it = "REG-09"; pt = "REG-09" }
    name = @{ ar = "تركيا بلا استعجال"; en = "Turkey Without Rush"; es = "Turquía sin Prisas"; it = "Turchia Senza Fretta"; pt = "Turquia Sem Pressa" }
    duration = @{ ar = "9 أيام / 8 ليالٍ"; en = "9 days / 8 nights"; es = "9 días / 8 noches"; it = "9 giorni / 8 notti"; pt = "9 dias / 8 noites" }
    minPax = @{ ar = "فردان"; en = "2 Pax"; es = "2 Pax"; it = "2 Pax"; pt = "2 Pax" }
    overview = @{
        ar = "كما يصفه اسمه تماماً، هو برنامج ""على الرايق"" مصمم للمسافر الذي يكره الجداول البرية الطويلة المرهقة. يتنقل البرنامج حصرياً بالطائرات ليربط بين المحطات الرئيسية الثلاث الكبرى (إسطنبول، كابادوكيا، وبحر إيجة) لضمان أقصى درجات الراحة والرفاهية."
        en = "As the name perfectly describes, this is a ""chill"" program designed for travelers who hate long, exhausting overland schedules. The program moves exclusively by air, connecting the three major hubs (Istanbul, Cappadocia, and the Aegean) to ensure maximum comfort and luxury."
        es = "Tal como lo describe su nombre, es un programa ""tranquilo"" diseñado para el viajero que odia los largos y agotadores itinerarios por carretera. El programa se desplaza exclusivamente en avión para conectar las tres grandes estaciones (Estambul, Capadocia y el Egeo), garantizando la máxima comodidad y lujo."
        it = "Come il nome descrive perfettamente, è un programma ""rilassato"" progettato per il viaggiatore che odia i lunghi e faticosi itinerari via terra. Il programma si sposta esclusivamente in aereo per collegare i tre grandi hub (Istanbul, Cappadocia e l'Egeo), garantendo il massimo comfort e lusso."
        pt = "Como o nome descreve perfeitamente, este é um programa ""na tranquilidade"" projetado para o viajante que odeia longos e cansativos itinerários terrestres. O programa se desloca exclusivamente por via aérea, conectando os três principais hubs (Istambul, Capadócia e o Egeu), garantindo o máximo conforto e luxo."
    }
    highlights = @{
        ar = @("جولة مريحة خالية من عناء السفر البري الطويل عبر شبكة طيران داخلي متكاملة.","استكشاف وادي الحب (Valle del Amor) البيئي والتاريخي الشهير في كابادوكيا.","رحلة مخصصة لزيارة معالم الينابيع الحرارية في باموكالي انطلاقاً من مقرك الساحلي.","توازن ممتاز بين الجولات التاريخية الموجهة والأوقات الحرة الشخصية.")
        en = @("A comfortable tour free from the hardship of long overland travel via an integrated domestic flight network.","Explore the famous ecological and historical Love Valley in Cappadocia.","A dedicated trip to visit the thermal springs of Pamukkale departing from your coastal base.","An excellent balance between guided historical tours and free personal time.")
        es = @("Un tour cómodo y libre de la fatiga de los largos viajes por carretera gracias a una red integrada de vuelos domésticos.","Explorar el famoso Valle del Amor ecológico e histórico en Capadocia.","Un viaje dedicado para visitar los manantiales termales de Pamukkale partiendo desde su base costera.","Un excelente equilibrio entre visitas históricas guiadas y tiempo libre personal.")
        it = @("Un tour comodo e libero dalla fatica dei lunghi viaggi via terra grazie a una rete integrata di voli domestici.","Esplorare il famoso Valle dell'Amore ecologico e storico in Cappadocia.","Un viaggio dedicato per visitare le sorgenti termali di Pamukkale partendo dalla vostra base costiera.","Un eccellente equilibrio tra tour storici guidati e tempo libero personale.")
        pt = @("Um tour confortável e livre do cansaço das longas viagens terrestres através de uma rede integrada de voos domésticos.","Explorar o famoso Vale do Amor ecológico e histórico na Capadócia.","Uma viagem dedicada para visitar as nascentes termais de Pamukkale partindo da sua base costeira.","Um excelente equilíbrio entre passeios históricos guiados e tempo livre pessoal.")
    }
    days = @(
        @{ day = "1–2"; meals = @{ ar = "إفطار + غداء في اليوم الثاني"; en = "Breakfast + Lunch on Day 2"; es = "Desayuno + Almuerzo el día 2"; it = "Colazione + Pranzo il giorno 2"; pt = "Café da manhã + Almoço no dia 2" }; description = @{ ar = "الوصول لإسطنبول، والقيام بجولة المدينة القديمة الكاملة التاريخية (آيا صوفيا خارجي، توبكابي، والجراند بازار)."; en = "Arrival in Istanbul. Full-day historical Old City tour (Hagia Sophia exterior, Topkapi Palace, Grand Bazaar)."; es = "Llegada a Estambul. Recorrido completo de la Ciudad Vieja (Santa Sofía exterior, Palacio de Topkapi, Gran Bazar)."; it = "Arrivo a Istanbul. Giro completo della Città Vecchia (Santa Sofia esterno, Palazzo di Topkapi, Gran Bazar)."; pt = "Chegada a Istambul. Tour completo da Cidade Velha (Santa Sofia exterior, Palácio de Topkapi, Grande Bazar)." } }
        @{ day = "3"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة سوق التوابل والبوسفور بالمركب نهاراً، وزيارة تقسيم والغالاطا، يليه الانتقال للمطار للطيران مباشرة إلى كابادوكيا والمبيت."; en = "Spice Bazaar tour and Bosphorus boat cruise during the day, visit Taksim and Galata, then transfer to airport for direct flight to Cappadocia, overnight."; es = "Recorrido del Bazar de las Especias y paseo en barco por el Bósforo, visita a Taksim y Gálata, luego traslado al aeropuerto para vuelo directo a Capadocia, alojamiento."; it = "Giro del Bazar delle Spezie e crociera in barca sul Bosforo, visita a Taksim e Galata, poi trasferimento in aeroporto per il volo diretto per la Cappadocia, pernottamento."; pt = "Tour do Bazar de Especiarias e cruzeiro de barco pelo Bósforo, visita a Taksim e Gálata, depois transfer para o aeroporto para voo direto para a Capadócia, pernoite." } }
        @{ day = "4"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة الوديان في كابادوكيا (جوريم، أواتش حصار، وادي الحب، والمدينة تحت الأرض)."; en = "Valleys tour in Cappadocia (Göreme, Uçhisar, Love Valley, underground city)."; es = "Recorrido por los valles de Capadocia (Göreme, Uçhisar, Valle del Amor, ciudad subterránea)."; it = "Giro delle valli in Cappadocia (Göreme, Uçhisar, Valle dell'Amore, città sotterranea)."; pt = "Passeio pelos vales da Capadócia (Göreme, Uçhisar, Vale do Amor, cidade subterrânea)." } }
        @{ day = "5"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "النقل إلى المطار للطيران من كابادوكيا إلى إزمير، النقل للفندق في كوشاداسي."; en = "Transfer to airport for flight from Cappadocia to Izmir, transfer to hotel in Kuşadası."; es = "Traslado al aeropuerto para volar de Capadocia a Esmirna, traslado al hotel en Kuşadası."; it = "Trasferimento in aeroporto per il volo dalla Cappadocia a Smirne, trasferimento in hotel a Kuşadası."; pt = "Transfer para o aeroporto para voo da Capadócia para Esmirna, transfer para o hotel em Kuşadası." } }
        @{ day = "6"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "رحلة يوم كامل بالسيارة من كوشاداسي لزيارة مدرجات باموكالي وآثار هيرابوليس والعودة لكوشاداسي."; en = "Full-day trip by car from Kuşadası to visit the Pamukkale travertines and Hierapolis ruins, returning to Kuşadası."; es = "Excursión de día completo en coche desde Kuşadası para visitar los travertinos de Pamukkale y las ruinas de Hierápolis, regreso a Kuşadası."; it = "Gita di un giorno intero in auto da Kuşadası per visitare i travertini di Pamukkale e le rovine di Hierapolis, ritorno a Kuşadası."; pt = "Viagem de dia inteiro de carro de Kuşadası para visitar os travertinos de Pamukkale e as ruínas de Hierápolis, retorno a Kuşadası." } }
        @{ day = "7"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة آثار أفسس الرومانية، وبيت مريم العذراء، ومصنع الجلود وعرض الأزياء."; en = "Tour of the Roman ruins of Ephesus, House of the Virgin Mary, leather factory, and fashion show."; es = "Recorrido por las ruinas romanas de Éfeso, Casa de la Virgen María, fábrica de cuero y desfile de moda."; it = "Giro delle rovine romane di Efeso, Casa della Vergine Maria, conceria e sfilata di moda."; pt = "Tour das ruínas romanas de Éfeso, Casa da Virgem Maria, fábrica de couro e desfile de moda." } }
        @{ day = "8"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "النقل للمطار للطيران من إزمير عودة إلى إسطنبول والمبيت."; en = "Transfer to airport for flight from Izmir back to Istanbul, overnight."; es = "Traslado al aeropuerto para volar de Esmirna de regreso a Estambul, alojamiento."; it = "Trasferimento in aeroporto per il volo da Smirne di ritorno a Istanbul, pernottamento."; pt = "Transfer para o aeroporto para voo de Esmirna de volta a Istambul, pernoite." } }
        @{ day = "9"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "التوصيل لمطار إسطنبول للمغادرة النهائية."; en = "Transfer to Istanbul Airport for final departure."; es = "Traslado al aeropuerto de Estambul para la salida final."; it = "Trasferimento all'aeroporto di Istanbul per la partenza finale."; pt = "Transfer para o aeroporto de Istambul para partida final." } }
    )
}

$p10 = [PSCustomObject]@{
    id = "REG-10"
    code = @{ ar = "REG-10"; en = "REG-10"; es = "REG-10"; it = "REG-10"; pt = "REG-10" }
    name = @{ ar = "الريفييرا التركية الممتدة مع فتحية"; en = "Extended Turkish Riviera with Fethiye"; es = "Riviera Turca con Fethiye"; it = "Riviera Turca con Fethiye"; pt = "Riviera Turca com Fethiye" }
    duration = @{ ar = "13 يوماً / 12 ليلة"; en = "13 days / 12 nights"; es = "13 días / 12 noches"; it = "13 giorni / 12 notti"; pt = "13 dias / 12 noites" }
    minPax = @{ ar = "فردان"; en = "2 Pax"; es = "2 Pax"; it = "2 Pax"; pt = "2 Pax" }
    overview = @{
        ar = "هذا هو البرنامج الأطول والأكثر فخامة لعشاق الطبيعة الساحلية والمياه الفيروزية؛ حيث يمتد ليجمع بين معالم الأناضول الكلاسيكية وأجمل منتجعين شاطئيين في تركيا على الإطلاق: بودروم وفتحية."
        en = "This is the longest and most luxurious program for lovers of coastal nature and turquoise waters, extending to combine classic Anatolian landmarks with Turkey's two most beautiful beach resorts: Bodrum and Fethiye."
        es = "Este es el programa más largo y lujoso para los amantes de la naturaleza costera y las aguas turquesas, extendiéndose para combinar los monumentos clásicos de Anatolia con los dos resorts playeros más bellos de Turquía: Bodrum y Fethiye."
        it = "Questo è il programma più lungo e lussuoso per gli amanti della natura costiera e delle acque turchesi, estendendosi per combinare i monumenti classici dell'Anatolia con le due più belle località balneari della Turchia: Bodrum e Fethiye."
        pt = "Este é o programa mais longo e luxuoso para os amantes da natureza costeira e águas turquesas, estendendo-se para combinar os marcos clássicos da Anatólia com os dois mais belos resorts de praia da Turquia: Bodrum e Fethiye."
    }
    highlights = @{
        ar = @("إقامة ممتدة ومريحة لـ 3 ليالٍ كاملة في إسطنبول في بداية الرحلة.","الجمع بين منتجع بودروم الفاخر ومنتجع فتحية الساحر في رحلة واحدة.","الاستمتاع بخدمة التوصيل بسيارات خاصة مع سائق بين المدن الساحلية.","قضاء 4 ليالٍ من الاستجمام الشاطئي الكامل بين بحر إيجة والبحر المتوسط.")
        en = @("An extended, comfortable 3-night stay in Istanbul at the start of the trip.","Combining the luxurious Bodrum resort with the charming Fethiye resort in one journey.","Enjoy private car transfer with driver between coastal cities.","Spend 4 nights of complete beach relaxation between the Aegean and Mediterranean seas.")
        es = @("Una estancia prolongada y confortable de 3 noches completas en Estambul al inicio del viaje.","Combinar el lujoso resort de Bodrum con el encantador resort de Fethiye en un solo viaje.","Disfrutar del servicio de traslado en coche privado con conductor entre las ciudades costeras.","Pasar 4 noches de completo descanso playero entre el mar Egeo y el Mediterráneo.")
        it = @("Un soggiorno prolungato e confortevole di 3 notti intere a Istanbul all'inizio del viaggio.","Combinare la lussuosa località di Bodrum con l'affascinante località di Fethiye in un unico viaggio.","Godere del servizio di trasferimento in auto privata con autista tra le città costiere.","Trascorrere 4 notti di completo relax balneare tra il Mar Egeo e il Mediterraneo.")
        pt = @("Uma estadia prolongada e confortável de 3 noites completas em Istambul no início da viagem.","Combinar o luxuoso resort de Bodrum com o encantador resort de Fethiye em uma única viagem.","Desfrutar do serviço de transferência em carro particular com motorista entre as cidades costeiras.","Passar 4 noites de completo relaxamento à beira-mar entre o Mar Egeu e o Mediterrâneo.")
    }
    days = @(
        @{ day = "1–3"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "قضاء 3 ليالٍ في إسطنبول شاملة جولة بازار التوابل والأسوار ومسجد رستم باشا، مع يوم حر."; en = "3 nights in Istanbul including a tour of the Spice Bazaar, city walls, and Rüstem Pasha Mosque, with one free day."; es = "3 noches en Estambul incluyendo un recorrido por el Bazar de las Especias, las murallas y la Mezquita de Rüstem Pasha, con un día libre."; it = "3 notti a Istanbul inclusa una visita al Bazar delle Spezie, le mura e la Moschea di Rüstem Pasha, con un giorno libero."; pt = "3 noites em Istambul incluindo um tour pelo Bazar de Especiarias, as muralhas e a Mesquita de Rüstem Pasha, com um dia livre." } }
        @{ day = "4"; meals = @{ ar = "إفطار صندوقي + عشاء"; en = "Picnic breakfast + Dinner"; es = "Desayuno de picnic + Cena"; it = "Colazione al sacco + Cena"; pt = "Café da manhã de piquenique + Jantar" }; description = @{ ar = "الانتقال للمطار للطيران إلى كابادوكيا. في الطريق زيارة مدينة أرضية وورشة خزف."; en = "Transfer to airport for flight to Cappadocia. En route, visit an underground city and a ceramic workshop."; es = "Traslado al aeropuerto para volar a Capadocia. En el camino, visita a una ciudad subterránea y un taller de cerámica."; it = "Trasferimento in aeroporto per il volo per la Cappadocia. Lungo il percorso, visita a una città sotterranea e a un laboratorio di ceramica."; pt = "Transfer para o aeroporto para voo para a Capadócia. No caminho, visita a uma cidade subterrânea e a uma oficina de cerâmica." } }
        @{ day = "5–6"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة وديان كابادوكيا والمنطاد الاختياري (اليوم 5)، ثم الانتقال براً في اليوم السادس لباموكالي وأثارها والينابيع الحرارية."; en = "Cappadocia valleys tour and optional hot air balloon (Day 5). Then overland to Pamukkale for its ruins and thermal springs (Day 6)."; es = "Recorrido por los valles de Capadocia y globo opcional (día 5). Luego traslado por carretera a Pamukkale para ver sus ruinas y manantiales termales (día 6)."; it = "Giro delle valli della Cappadocia e mongolfiera opzionale (giorno 5). Poi trasferimento via terra a Pamukkale per le sue rovine e sorgenti termali (giorno 6)."; pt = "Passeio pelos vales da Capadócia e balão de ar quente opcional (dia 5). Depois viagem terrestre para Pamukkale para suas ruínas e nascentes termais (dia 6)." } }
        @{ day = "7"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة أفسس الأثرية، وبيت مريم العذراء، ومصنع الجلود، والانتقال لفندق إزمير أو كوشاداسي."; en = "Tour of the archaeological site of Ephesus, House of the Virgin Mary, leather factory, then transfer to hotel in Izmir or Kuşadası."; es = "Recorrido por el sitio arqueológico de Éfeso, Casa de la Virgen María, fábrica de cuero, luego traslado al hotel en Esmirna o Kuşadası."; it = "Giro del sito archeologico di Efeso, Casa della Vergine Maria, conceria, poi trasferimento in hotel a Smirne o Kuşadası."; pt = "Tour do sítio arqueológico de Éfeso, Casa da Virgem Maria, fábrica de couro, depois transfer para hotel em Esmirna ou Kuşadası." } }
        @{ day = "8–9"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "الانتقال بسيارة وسائق إلى بودروم الساحلية لقضاء ليلتين حرتين بالكامل."; en = "Private car transfer with driver to the coastal resort of Bodrum for 2 completely free nights."; es = "Traslado en coche privado con conductor al resort costero de Bodrum para 2 noches completamente libres."; it = "Trasferimento in auto privata con autista alla località costiera di Bodrum per 2 notti completamente libere."; pt = "Transferência em carro particular com motorista para o resort costeiro de Bodrum para 2 noites completamente livres." } }
        @{ day = "10–11"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "التحرك بسيارة وسائق إلى منتجع فتحية (Fethiye) الشهير، وقضاء ليلتين حرتين للاستجمام."; en = "Private car transfer with driver to the famous resort of Fethiye for 2 free nights of relaxation."; es = "Traslado en coche privado con conductor al famoso resort de Fethiye para 2 noches libres de descanso."; it = "Trasferimento in auto privata con autista alla famosa località di Fethiye per 2 notti libere di relax."; pt = "Transferência em carro particular com motorista para o famoso resort de Fethiye para 2 noites livres de relaxamento." } }
        @{ day = "12"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "النقل للمطار القريب للطيران عودة إلى إسطنبول والمبيت."; en = "Transfer to the nearby airport for return flight to Istanbul, overnight."; es = "Traslado al aeropuerto cercano para vuelo de regreso a Estambul, alojamiento."; it = "Trasferimento all'aeroporto vicino per il volo di ritorno a Istanbul, pernottamento."; pt = "Transfer para o aeroporto próximo para voo de volta a Istambul, pernoite." } }
        @{ day = "13"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "التوصيل للمطار والمغادرة النهائية."; en = "Transfer to airport for final departure."; es = "Traslado al aeropuerto para la salida final."; it = "Trasferimento in aeroporto per la partenza finale."; pt = "Transfer para o aeroporto para partida final." } }
    )
}

$p11 = [PSCustomObject]@{
    id = "REG-11"
    code = @{ ar = "REG-11"; en = "REG-11"; es = "REG-11"; it = "REG-11"; pt = "REG-11" }
    name = @{ ar = "أنطاليا والساحل المتوسطي"; en = "Andalía (Antalya & Mediterranean Coast)"; es = "Andalía"; it = "Andalía"; pt = "Andalía" }
    duration = @{ ar = "10 أيام / 9 ليالٍ"; en = "10 days / 9 nights"; es = "10 días / 9 noches"; it = "10 giorni / 9 notti"; pt = "10 dias / 9 noites" }
    minPax = @{ ar = "فردان"; en = "2 Pax"; es = "2 Pax"; it = "2 Pax"; pt = "2 Pax" }
    overview = @{
        ar = "رحلة تأخذك إلى قلب الساحل الفيروزي التركي المطل على البحر الأبيض المتوسط. يدمج البرنامج بشكل رائع بين سحر المتاحف المفتوحة في كابادوكيا والاسترخاء في أنطاليا (عروس المتوسط)، قبل الانطلاق لزيارة عجائب باموكالي وأفسس التاريخية."
        en = "A journey taking you to the heart of the turquoise Turkish coast overlooking the Mediterranean Sea. The program beautifully blends the charm of Cappadocia's open-air museums with relaxation in Antalya (the ""Bride of the Mediterranean""), before heading to the wonders of Pamukkale and the historic ruins of Ephesus."
        es = "Un viaje que te lleva al corazón de la costa turquesa turca con vistas al mar Mediterráneo. El programa combina maravillosamente el encanto de los museos al aire libre de Capadocia con la relajación en Antalya (la ""Novia del Mediterráneo""), antes de partir hacia las maravillas de Pamukkale y las ruinas históricas de Éfeso."
        it = "Un viaggio che ti porta nel cuore della costa turchese turca affacciata sul Mar Mediterraneo. Il programma fonde meravigliosamente il fascino dei musei all'aperto della Cappadocia con il relax ad Antalya (la ""Sposa del Mediterraneo""), prima di partire per le meraviglie di Pamukkale e le rovine storiche di Efeso."
        pt = "Uma viagem que leva você ao coração da costa turquesa turca com vista para o Mar Mediterrâneo. O programa combina maravilhosamente o charme dos museus ao ar livre da Capadócia com relaxamento em Antália (a ""Noiva do Mediterrâneo""), antes de partir para as maravilhas de Pamukkale e as ruínas históricas de Éfeso."
    }
    highlights = @{
