    days = @(
        @{ day = "1–4"; meals = $null; description = @{ ar = "قضاء الأيام الأولى بين إسطنبول (جولة المدينة القديمة، رحلة البوسفور وتقسيم) ثم كابادوكيا وزيارة معالمها الأساسية (وادي جوريم، المدينة الأرضية أوزكوناك أو ساراتلي مع وجبات الإفطار والعشاء المعتادة)."; en = "Spend the first days between Istanbul (Old City tour, Bosphorus cruise, Taksim) then Cappadocia visiting its main landmarks (Göreme Valley, Özkonak or Saratlı underground city) with standard breakfast and dinner meals."; es = "Pasar los primeros días entre Estambul (recorrido por la Ciudad Vieja, crucero por el Bósforo, Taksim) y luego Capadocia visitando sus principales lugares (Valle de Göreme, ciudad subterránea de Özkonak o Saratlı) con las comidas habituales de desayuno y cena."; it = "Trascorrere i primi giorni tra Istanbul (giro della Città Vecchia, crociera sul Bosforo, Taksim) e poi la Cappadocia visitando i suoi principali luoghi (Valle di Göreme, città sotterranea di Özkonak o Saratlı) con i pasti standard di colazione e cena."; pt = "Passar os primeiros dias entre Istambul (tour da Cidade Velha, cruzeiro no Bósforo, Taksim) e depois a Capadócia visitando seus principais pontos (Vale de Göreme, cidade subterrânea de Özkonak ou Saratlı) com as refeições padrão de café da manhã e jantar." } }
        @{ day = "5"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "النقل عبر طريق بري إلى مدينة أنطاليا الساحلية (Antalya) والوصول للفندق والمبيت."; en = "Overland transfer to the coastal city of Antalya, arrival at hotel, overnight."; es = "Traslado por carretera a la ciudad costera de Antalya, llegada al hotel, alojamiento."; it = "Trasferimento via terra alla città costiera di Antalya, arrivo in hotel, pernottamento."; pt = "Transferência terrestre para a cidade costeira de Antália, chegada ao hotel, pernoite." } }
        @{ day = "6"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "يوم حر بالكامل في أنطاليا للاستجمام والنشاط الشخصي."; en = "Completely free day in Antalya for relaxation and personal activities."; es = "Día completamente libre en Antalya para descanso y actividades personales."; it = "Giornata completamente libera ad Antalya per relax e attività personali."; pt = "Dia completamente livre em Antália para descanso e atividades pessoais." } }
        @{ day = "7"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "الانتقال مع سائق من أنطاليا إلى باموكالي؛ حيث يتم مقابلة المرشد المحلي لزيارة مدرجات الينابيع وآثار هيرابوليس والمبيت."; en = "Transfer with driver from Antalya to Pamukkale, meeting a local guide to visit the travertine terraces and Hierapolis ruins, overnight."; es = "Traslado con conductor de Antalya a Pamukkale, encuentro con guía local para visitar las terrazas de travertino y las ruinas de Hierápolis, alojamiento."; it = "Trasferimento con autista da Antalya a Pamukkale, incontro con una guida locale per visitare le terrazze di travertino e le rovine di Hierapolis, pernottamento."; pt = "Transferência com motorista de Antália para Pamukkale, encontro com um guia local para visitar os terraços de travertino e as ruínas de Hierápolis, pernoite." } }
        @{ day = "8"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "الانتقال لزيارة أفسس وبيت مريم ومصنع الجلود وعرض الأزياء والمبيت في كوشاداسي أو إزمير."; en = "Transfer to visit Ephesus, House of the Virgin Mary, leather factory and fashion show, overnight in Kuşadası or Izmir."; es = "Traslado para visitar Éfeso, Casa de la Virgen María, fábrica de cuero y desfile de moda, alojamiento en Kuşadası o Esmirna."; it = "Trasferimento per visitare Efeso, Casa della Vergine Maria, conceria e sfilata di moda, pernottamento a Kuşadası o Smirne."; pt = "Transferência para visitar Éfeso, Casa da Virgem Maria, fábrica de couro e desfile de moda, pernoite em Kuşadası ou Esmirna." } }
